{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires deriving the force law for a polymer chain under adiabatic (constant entropy) conditions, which differs from the standard isothermal case. This requires calculating the partition function, the entropy, and the temperature dependence of the extension.",
  "helpers": [
    {
      "label": "statistical_mechanics_expert",
      "instructions": "Derive the partition function Z(x, n, l, T) for a freely jointed chain of n segments of length l extended to a total end-to-end distance x. Express the Helmholtz free energy A(x, T) and the entropy S(x, T) as functions of x, n, l, and T. Use the high-temperature/small-extension approximation where applicable."
    },
    {
      "label": "thermodynamics_expert",
      "instructions": "Given the entropy S(x, T) derived from the statistical mechanics step, apply the adiabatic condition (dS = 0) to find the relationship between temperature T and extension x. Then, use the thermodynamic identity for force under adiabatic conditions, F = (dE/dx)_S or F = T(dS/dx)_E, to derive the force law F(x)."
    }
  ],
  "synthesis_brief": "Combine the entropy expression from the first helper with the adiabatic constraint to find how temperature scales with extension. Substitute this scaling into the force derivation to obtain the final F(x) formula, ensuring the power of x and the coefficient are correctly determined for the adiabatic case."
}

